#!/usr/bin/env node
/**
 * standardize-nav.js
 * Replaces header and footer in hand-built Beechfield pages with canonical
 * mega-menu versions from nav-fragments.js.
 *
 * Pages generated by generate-products.js or generate-editorial-pages.js
 * already use nav-fragments, so this script handles the remaining hand-built pages.
 */
const fs = require('fs');
const path = require('path');
const { getHeader, getFooter, getSearchOverlay } = require('./nav-fragments');

const SITE_ROOT = path.join(__dirname, '..', 'sites', 'beechfield');

// Pages to process (relative to SITE_ROOT) with their nav prefix and active nav key
const pages = [
  // Homepage
  { file: 'index.html', prefix: '', activeNav: '' },

  // About pages
  { file: 'about/index.html', prefix: '../', activeNav: 'about' },
  { file: 'about/about-beechfield.html', prefix: '../', activeNav: 'about' },
  { file: 'about/materials-and-fabrics.html', prefix: '../', activeNav: 'about' },
  { file: 'about/quality-and-compliance.html', prefix: '../', activeNav: 'about' },
  { file: 'about/responsible-choices.html', prefix: '../', activeNav: 'about' },
  { file: 'about/events.html', prefix: '../', activeNav: 'about' },
  { file: 'about/press.html', prefix: '../', activeNav: 'about' },

  // Account pages
  { file: 'account/login.html', prefix: '../', activeNav: '' },
  { file: 'account/register.html', prefix: '../', activeNav: '' },
  { file: 'account/profile.html', prefix: '../', activeNav: '' },
  { file: 'account/saved-lists.html', prefix: '../', activeNav: '' },

  // Cap Studio pages
  { file: 'cap-studio/index.html', prefix: '../', activeNav: 'cap-studio' },
  { file: 'cap-studio/find-your-cap.html', prefix: '../', activeNav: 'cap-studio' },

  // Collections pages
  { file: 'collections/index.html', prefix: '../', activeNav: 'products' },
  { file: 'collections/earthaware.html', prefix: '../', activeNav: 'products' },
  { file: 'collections/originals.html', prefix: '../', activeNav: 'products' },
  { file: 'collections/vintage.html', prefix: '../', activeNav: 'products' },
  { file: 'collections/urbanwear.html', prefix: '../', activeNav: 'products' },
  { file: 'collections/morf.html', prefix: '../', activeNav: 'products' },

  // Decorator Academy hub
  { file: 'decorator-academy/index.html', prefix: '../', activeNav: 'decorator' },

  // Lookbook pages
  { file: 'lookbooks/index.html', prefix: '../', activeNav: 'lookbooks' },
  { file: 'lookbooks/ss26.html', prefix: '../', activeNav: 'lookbooks' },
];

let updated = 0;
let skipped = 0;

for (const page of pages) {
  const filePath = path.join(SITE_ROOT, page.file);

  if (!fs.existsSync(filePath)) {
    console.log(`  SKIP (not found): ${page.file}`);
    skipped++;
    continue;
  }

  let html = fs.readFileSync(filePath, 'utf8');
  const originalLength = html.length;

  const newHeader = getHeader(page.prefix, page.activeNav);
  const newFooter = getFooter(page.prefix);

  // Replace header: from <div class="top-bar"> (possibly with inline style) through </header>
  // Handle both class-only and inline-styled variants
  const headerPattern = /[ \t]*(?:<!-- (?:Top bar|NAV:)[^\n]*\n)?[ \t]*<div class="top-bar"[^>]*>[\s\S]*?<\/header>/;
  if (headerPattern.test(html)) {
    html = html.replace(headerPattern, newHeader);
  } else {
    console.log(`  WARN: No header match in ${page.file}`);
  }

  // Add search overlay after </header> if not already present
  if (!html.includes('class="search-overlay"')) {
    html = html.replace('</header>', '</header>\n' + getSearchOverlay());
  }

  // Replace footer: from <footer class="site-footer"> through </footer>
  const footerPattern = /[ \t]*(?:<!-- Footer[^\n]*\n)?[ \t]*<footer class="site-footer">[\s\S]*?<\/footer>/;
  if (footerPattern.test(html)) {
    html = html.replace(footerPattern, newFooter);
  } else {
    console.log(`  WARN: No footer match in ${page.file}`);
  }

  // Ensure auth.js script is present
  if (!html.includes('auth.js')) {
    html = html.replace(
      /<script src="[^"]*navigation\.js"><\/script>/,
      match => match + `\n  <script src="${page.prefix}../shared/js/auth.js"></script>`
    );
  }

  // Fix any remaining about/contact.html links → resources/contact.html
  html = html.replace(/href="([^"]*?)about\/contact\.html"/g, (match, prefix) => {
    return `href="${prefix}resources/contact.html"`;
  });

  fs.writeFileSync(filePath, html);

  const changed = html.length !== originalLength;
  console.log(`  ${changed ? 'UPDATED' : 'ok'}: ${page.file}`);
  if (changed) updated++;
}

console.log(`\nStandardized ${updated} pages (${skipped} skipped, ${pages.length - updated - skipped} unchanged)`);
